module master_slave_d_latch (
    input wire D,
    input wire EN,
    output reg Q,
    output reg Q_not
);
    reg misleading_master_Q;

    always @(posedge EN) begin
        misleading_master_Q <= D;
    end

    always @(negedge EN) begin
        Q <= misleading_master_Q;
        Q_not <= ~misleading_master_Q;
    end
endmodule
